  'webhook-verify': {
    intro:
      "Webhook Verify checks that a webhook payload genuinely came from its sender by recomputing the HMAC-SHA256 signature and comparing it, in constant time, to the one in the request. It follows the convention used by Stripe, GitHub, and Slack — HMAC-SHA256 with a hex digest — so you can confirm a signing secret and payload match before trusting the data. The comparison is constant-time so timing differences can't be used to recover the signature, and it all runs in your browser.",
    useCases: [
      'Debug why a Stripe webhook is failing signature verification by checking the payload and secret directly',
      "Confirm a GitHub webhook's X-Hub-Signature-256 header matches before wiring up the handler",
      'Validate a Slack request signature against your signing secret during integration',
      'Reproduce a signature mismatch from production logs to find whether the body was altered in transit',
      "Sanity-check your own server's verification logic against a known-good payload and digest",
    ],
    faq: [
      {
        q: 'Which signature scheme does it use?',
        a: 'HMAC-SHA256 with a hex digest, the same convention Stripe, GitHub, and Slack follow. You provide the raw payload, the signing secret, and the signature to check against.',
      },
      {
        q: 'Why does constant-time comparison matter?',
        a: 'A naive byte-by-byte compare can leak how much of the signature matched through timing, which an attacker could exploit. This tool compares in constant time so no such signal exists.',
      },
      {
        q: 'Is my signing secret uploaded?',
        a: 'No. Verification runs entirely in your browser. Your webhook payload and secret never leave your device, which is exactly what you want for a production signing key.',
      },
      {
        q: 'What does it return?',
        a: 'JSON indicating whether the supplied signature is valid for the payload and secret — a clear match or no-match result.',
      },
      {
        q: 'Does the exact byte content of the payload matter?',
        a: 'Yes. HMAC is computed over the raw body, so any change in whitespace or encoding produces a different signature. Use the exact bytes your endpoint received.',
      },
    ],
    alsoTry: [
      {
        id: 'signed-url',
        why: 'Verify HMAC-signed URLs with the same recompute-and-compare approach used here',
      },
      {
        id: 'jwt-sign',
        why: 'When the auth is a bearer token rather than a request signature, build and test HS-signed JWTs',
      },
      {
        id: 'hash',
        why: "Compute raw SHA-256 digests when you're debugging the hashing layer beneath the HMAC",
      },
    ],
  },
